function.body:
TYPE RECORD IS REF CURSOR;
  Cur_Parameter RECORD;
  vRecord     RECORD;
  Cur_Liquidate RECORD;

  v_Client_ID VARCHAR2(32);

  v_Org_ID VARCHAR2(32);

  v_User_ID VARCHAR2(32) ;

  v_ResultStr VARCHAR2(2000) := '';  

  v_Record_ID  VARCHAR2(32);

  v_Message VARCHAR2(2000):='';

  V_Processing Varchar2(60);

  v_Campaign_ID  VARCHAR2(32);


BEGIN

    --  Update AD_PInstance
    DBMS_OUTPUT.PUT_LINE('Updating PInstance - Processing ' || PInstance_ID) ;
    v_ResultStr := 'PInstanceNotFound';
    AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'Y', NULL, NULL) ;

    BEGIN --BODY

        -- Get Parameters
        v_ResultStr := 'ReadingParameters';
        FOR Cur_Parameter IN (
            SELECT i.Record_ID,
                i.AD_User_ID,
                i.AD_Client_ID,
                i.AD_Org_ID
            FROM AD_PInstance i
            WHERE i.AD_PInstance_ID = PInstance_ID
        ) LOOP

            v_Record_ID := Cur_Parameter.Record_ID;
            v_Client_ID := Cur_Parameter.AD_Client_ID;
            v_Org_ID := Cur_Parameter.AD_Org_ID;
            v_User_ID := Cur_Parameter.AD_User_ID;

        END LOOP; -- End Get Parameter

        SELECT docstatus, em_ssip_importstatus, processing INTO vRecord FROM c_order WHERE c_order_id = V_Record_Id;

        IF vRecord.processing = 'Y' THEN
            v_Message := '@Processing@';
            AD_UPDATE_PINSTANCE(Pinstance_Id, Null, 'N', 0, v_Message);
            RETURN;
        END IF;

        IF vRecord.em_ssip_importstatus = 'LL' THEN
            v_Message := '@SSIP_SettledDocument@';
            AD_UPDATE_PINSTANCE(Pinstance_Id, Null, 'N', 0, v_Message);
            RETURN;
        END IF;

        -- Set processing 'Y'
        IF vRecord.DocStatus = 'CO' THEN
            UPDATE c_order SET DocAction = 'RE' WHERE c_order_id = V_Record_Id;
            C_ORDER_POST1(NULL, v_Record_ID);
        END IF;

        UPDATE c_order SET Processing = 'Y' WHERE c_order_id = V_Record_Id;

        -- BEGIN FOR LIQUIDATE
        FOR Cur_Liquidate IN (
            SELECT priceactual, em_ssip_realcost, c_orderline_id
            FROM c_orderline
            WHERE c_order_id = V_Record_Id AND qtyordered <> 0
        ) LOOP

            UPDATE c_orderline  SET priceactual = Cur_Liquidate.em_ssip_realcost, pricestd = Cur_Liquidate.em_ssip_realcost
            WHERE c_orderline_id = Cur_Liquidate.c_orderline_id;

        END LOOP;

        SELECT COALESCE((
                SELECT to_char(C_Campaign_ID) FROM c_order WHERE c_order_id = V_Record_Id AND em_ssip_importstatus IN ('LL','NL')
            ), 'ND')
        INTO v_Campaign_ID
        FROM dual;

        IF v_Campaign_ID <> 'ND' THEN
            UPDATE C_Campaign SET ISACTIVE='N' WHERE C_Campaign_ID = v_Campaign_ID;
        END IF;
        -- END FOR LIQUIDATE

        -- Set processing 'N'
        IF vRecord.DocStatus = 'CO' THEN
            UPDATE c_order SET Processing = 'N', DocAction = 'CO', em_ssip_importstatus = 'LL' WHERE c_order_id = V_Record_Id;
            C_ORDER_POST1(NULL, v_Record_ID);
        ELSE
            UPDATE c_order SET Processing = 'N', em_ssip_importstatus = 'LL' WHERE c_order_id = V_Record_Id;
        END IF;

        DBMS_OUTPUT.PUT_LINE('Updating PInstance - Finished ' || v_Message) ;

        AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 1, v_Message) ;

        RETURN;


    END; --BODY

    EXCEPTION WHEN OTHERS THEN
        ROLLBACK;
        -- Set processing 'N'
        UPDATE c_order SET Processing = 'N' WHERE c_order_id = V_Record_Id;
        v_ResultStr:= '@ERROR=' || SQLERRM;
        DBMS_OUTPUT.PUT_LINE(v_ResultStr) ;
        AD_UPDATE_PINSTANCE(PInstance_ID, NULL, 'N', 0, v_ResultStr) ;
        RETURN;
END SSIP_GET_AMOUNTNET_INVOICE
